function mergeKeys(target, source) {
  if (!target || typeof target !== 'object') return
  for (const key of Object.keys(source)) {
    if (!(key in target)) target[key] = source[key]
  }
}

function mergeKeysOverwrite(target, source) {
  if (!target || typeof target !== 'object') return
  for (const key of Object.keys(source)) target[key] = source[key]
}

const localesToProcess = ['ja', 'zh', 'zh-TW', 'es', 'pt', 'pt-BR', 'fr', 'de', 'it', 'nl', 'pl', 'sv', 'ru', 'uk', 'tr', 'ar', 'fa', 'hi', 'bn', 'id', 'ms', 'vi', 'th']
const additionalKeysPath = path.join(__dirname, 'additional-locale-keys.json')
const ADDITIONAL_KEYS = fs.existsSync(additionalKeysPath) ? JSON.parse(fs.readFileSync(additionalKeysPath, 'utf8')) : {}

for (const locale of localesToProcess) {
  const filePath = path.join(MESSAGES_DIR, `${locale}.json`)
  if (!fs.existsSync(filePath)) {
    console.warn(`Skip ${locale}: file not found`)
    continue
  }
  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'))
  const translations = { ...EN_FALLBACK, ...(NEW_KEYS[locale] || {}) }
  for (const [ns, keys] of Object.entries(translations)) {
    if (!data[ns]) data[ns] = {}
    mergeKeys(data[ns], keys)
  }
  const extra = ADDITIONAL_KEYS[locale]
  if (extra) {
    for (const [ns, keys] of Object.entries(extra)) {
      if (!data[ns]) data[ns] = {}
      mergeKeysOverwrite(data[ns], keys)
    }
  }
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n', 'utf8')
  console.log(`Merged ${locale}.json`)
}

console.log('Done.')
